import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

const FluidSimulation: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;

    const resize = () => {
      const parent = canvas.parentElement;
      if (parent) {
        // Handle high DPI displays for crisp rendering
        const dpr = window.devicePixelRatio || 1;
        const rect = parent.getBoundingClientRect();

        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;

        ctx.scale(dpr, dpr);
        canvas.style.width = `${rect.width}px`;
        canvas.style.height = `${rect.height}px`;
      }
    };

    // Initial resize
    resize();
    window.addEventListener('resize', resize);

    // Simulation Config
    const N = 40; // Grid resolution (N x N)
    const colorScale = d3.scaleSequential(d3.interpolateTurbo).domain([-2.5, 2.5]);

    const render = () => {
      const width = parseFloat(canvas.style.width);
      const height = parseFloat(canvas.style.height);

      ctx.clearRect(0, 0, width, height);

      // Clear background
      ctx.fillStyle = '#ffffff'; 
      ctx.fillRect(0, 0, width, height);

      // --- Mathematical Modeling: Wave Equation Superposition ---
      // f(x,y,t) = sin(r - vt) + interfering waves
      const getValue = (x: number, y: number, t: number) => {
        const dx = x - N/2;
        const dy = y - N/2;
        const dist = Math.sqrt(dx*dx + dy*dy);

        // Superposition of radial wave and planar waves
        return Math.sin(dist * 0.4 - t * 2) + 
               Math.sin(x * 0.3 + t) * Math.cos(y * 0.2 + t) +
               Math.sin(dx * 0.15 + dy * 0.15 + t * 0.5);
      };

      // --- 3D Projection (Isometric-ish) ---
      const project = (x: number, y: number, z: number) => {
        // Scale factor to fit canvas
        const scale = Math.min(width, height) / (N * 2.2);

        // Isometric projection formulas
        // x' = (x - y) * cos(30)
        // y' = (x + y) * sin(30) - z
        const isoX = (x - y) * 0.866; // cos(30)
        const isoY = (x + y) * 0.5 - z * 0.6; // sin(30), flattened z

        return {
          x: width / 2 + isoX * scale * 1.5,
          y: height / 2 + isoY * scale * 1.5 - height / 10 // center offset
        };
      };

      // Grid physical spacing
      const spacing = 1.2;

      // --- Painter's Algorithm (Back-to-Front Rendering) ---
      // Pre-calculate all points
      const points: any[] = [];
      for (let i = 0; i <= N; i++) {
        points[i] = [];
        for (let j = 0; j <= N; j++) {
          const z = getValue(i, j, time);
          points[i][j] = {
            ...project((i - N/2) * spacing, (j - N/2) * spacing, z),
            z
          };
        }
      }

      ctx.lineWidth = 1;

      // Render Quads
      // Iterate so we draw from "back" (top of screen) to "front" (bottom)
      for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
           const p1 = points[i][j];
           const p2 = points[i+1][j];
           const p3 = points[i+1][j+1];
           const p4 = points[i][j+1];

           // Calculate average height for color
           const avgZ = (p1.z + p2.z + p3.z + p4.z) / 4;

           ctx.beginPath();
           ctx.moveTo(p1.x, p1.y);
           ctx.lineTo(p2.x, p2.y);
           ctx.lineTo(p3.x, p3.y);
           ctx.lineTo(p4.x, p4.y);
           ctx.closePath();

           // Fill with heatmap color
           ctx.fillStyle = colorScale(avgZ);
           ctx.fill();

           // Subtle stroke for mesh definition
           ctx.strokeStyle = 'rgba(0,0,0,0.05)';
           ctx.stroke();
        }
      }

      time += 0.02; // Animation speed
      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="w-full h-full relative bg-white rounded-2xl overflow-hidden border border-gray-200 shadow-sm">
      <div className="absolute top-4 left-4 z-10 bg-white/90 backdrop-blur-sm px-4 py-2 rounded-full border border-gray-200 shadow-sm flex items-center gap-2">
        <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
        <span className="text-xs font-bold text-gray-600 uppercase tracking-wider">Live Simulation</span>
      </div>
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

export default FluidSimulation;

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { ChevronLeft, ChevronRight, Info, Activity, Droplets, Zap, Truck, TrendingUp, Bug } from 'lucide-react';

interface ModelConfig {
  id: string;
  title: string;
  category: string;
  icon: React.ElementType;
  description: string;
  colorInterpolator: (t: number) => string;
  equation: (x: number, y: number, t: number, N: number) => number;
}

const models: ModelConfig[] = [
  {
    id: 'fluid',
    title: 'Fluid Dynamics',
    category: 'Physics',
    icon: Droplets,
    description: 'Simulating wave interference and ripple propagation using partial differential equations (PDEs).',
    colorInterpolator: d3.interpolateTurbo,
    equation: (x, y, t, N) => {
      const dx = x - N/2;
      const dy = y - N/2;
      const dist = Math.sqrt(dx*dx + dy*dy);
      return Math.sin(dist * 0.4 - t * 2) + 
             Math.sin(x * 0.3 + t) * Math.cos(y * 0.2 + t) +
             Math.sin(dx * 0.15 + dy * 0.15 + t * 0.5);
    }
  },
  {
    id: 'epidemic',
    title: 'Epidemic Spread (SIR)',
    category: 'Biology',
    icon: Bug,
    description: 'Spatial modeling of disease diffusion. Peaks represent high infection density radiating from ' + 
                 'an epicenter, simulating how viruses spread through populations.',
    colorInterpolator: d3.interpolateMagma,
    equation: (x, y, t, N) => {
      // Expanding ring of infection
      const dx = x - N/2;
      const dy = y - N/2;
      const r = Math.sqrt(dx*dx + dy*dy);
      const wave = Math.exp(-Math.pow(r - (t * 5) % 40, 2) / 20); // Moving ring
      const background = Math.sin(x * 0.5) * Math.cos(y * 0.5) * 0.2;
      return wave * 4 + background;
    }
  },
  {
    id: 'reaction',
    title: 'Turing Patterns',
    category: 'Chemistry',
    icon: Zap,
    description: 'Reaction-Diffusion systems explaining patterns in nature (e.g., zebra stripes, cheetah spots). ' +
                 'Represents the interaction between activator and inhibitor chemicals.',
    colorInterpolator: d3.interpolateViridis,
    equation: (x, y, t, N) => {
      // Standing wave-like patterns
      return Math.sin(x * 0.5 + t * 0.5) * Math.cos(y * 0.5 - t * 0.2) + 
             Math.sin(x * 0.8 - t * 0.3) * Math.sin(y * 0.8 + t * 0.1) * 1.5;
    }
  },
  {
    id: 'traffic',
    title: 'Traffic Shockwaves',
    category: 'Civil Eng.',
    icon: Truck,
    description: 'Phantom traffic jams modeled as density waves. ' +
                 'High peaks indicate congestion moving upstream against the flow of traffic.',
    colorInterpolator: d3.interpolateRdYlGn, // Red=Jam, Green=Free
    equation: (x, y, t, N) => {
      // Diagonal movement representing flow on a highway network
      const flow = (x + y) * 0.4 - t * 2;
      // Sawtooth-like wave for stop-and-go traffic
      const jam = Math.sin(flow) + 0.5 * Math.sin(2 * flow); 
      // Add some "lane changing" noise
      return jam * 1.5 + Math.cos(x - y) * 0.5;
    }
  },
  {
    id: 'heat',
    title: 'Heat Diffusion',
    category: 'Thermodynamics',
    icon: Activity,
