import React, { useState } from 'react';
import { ClipboardCheck, User, Mail, Calendar, CheckCircle, Loader2 } from 'lucide-react';

const AttendanceForm: React.FC = () => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    event: 'General Body Meeting',
    date: new Date().toISOString().split('T')[0]
  });
  const [status, setStatus] = useState<'idle' | 'submitting' | 'success'>('idle');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('submitting');
    // Simulate network request
    setTimeout(() => {
      setStatus('success');
    }, 1500);
  };

  const resetForm = () => {
    setFormData({
      firstName: '',
      lastName: '',
      email: '',
      event: 'General Body Meeting',
      date: new Date().toISOString().split('T')[0]
    });
    setStatus('idle');
  };

  if (status === 'success') {
    return (
      <div className="max-w-md mx-auto mt-8 bg-white rounded-xl shadow-lg p-8 text-center border border-gray-100 animate-in fade-in zoom-in duration-300">
