    const d = new Date(dateString);
    const year = d.getFullYear();
    // Autumn: Aug 26 - Jan 15
    // Spring: Jan 16 - July 1
    // (Simplifying year logic for demo purposes to match the mock data year)

    // Check if Spring (Jan 16 - July 1)
    const springStart = new Date(`${year}-01-16`);
    const springEnd = new Date(`${year}-07-01`);

    if (d >= springStart && d <= springEnd) {
        return { name: 'Spring', start: springStart, end: springEnd };
    } else {
        // Default to Autumn logic (handling year wrap usually requires more complex logic, 
        // but for this demo assuming current academic year flow)
        return { name: 'Autumn', start: new Date(`${year}-08-26`), end: new Date(`${year+1}-01-15`) }; 
