    // Spring: Jan 11 - Apr 26
    const isSpring = d.getMonth() < 6;

    if (isSpring) {
        return { name: 'Spring', start: new Date(`${year}-01-11`), end: new Date(`${year}-04-26`) };
    } else {
        return { name: 'Autumn', start: new Date(`${year}-08-25`), end: new Date(`${year}-12-09`) }; 
    }
  };

