                  <span className="flex items-center gap-1.5">
                    <span className="w-2.5 h-2.5 rounded-full bg-red-500"></span>
                    &lt; 50% Inactive
                  </span>
                </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

